import os
import logging
from azure.storage.blob import BlobServiceClient, BlobClient
from dotenv import load_dotenv

load_dotenv()

def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    blob_path = req.params.get("blobPath")

    if not blob_path:
        return func.HttpResponse(
            400,
            "Please pass a valid blob path in the query string or in the request body",
        )

    try:
        blob_client = BlobClient.from_blob_url(
            os.getenv("STORAGE_ACCOUNT"),
            os.getenv("STORAGE_CONTAINER"),
            blob_path,
        )

        with open("./output", "wb") as f:
            f.write(blob_client.download_blob().readall())

    except Exception as e:
        logging.error("Failed to download file from blob storage", exc_info=True)
        return func.HttpResponse(
            500, "Internal Server Error", str(e)
        )

    return func.HttpResponse(
        200, f"File {blob_path} downloaded successfully"
    )